#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 4005;
int n,m,a[N][N],s[N][N],X,Y;
int st[N][20],lg2[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int query(int l,int r){
    int k=lg2[r-l+1];
    return max(st[l][k],st[r-(1<<k)+1][k]);
}
int main(){
    //freopen("an2dl.in","r",stdin);
    //freopen("an2dl.out","w",stdout);
    n=read(),m=read();
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)a[i][j]=read();
    X=read(),Y=read();
    for(int i=2;i<=max(n,m);i++)lg2[i]=lg2[i/2]+1;
    for(int k=1;k<=n;k++){
        for(int i=1;i<=m;i++)st[i][0]=a[k][i];
        for(int j=1;(1<<j)<=m;j++)
            for(int i=1;i+(1<<j)-1<=m;i++)
                st[i][j]=max(st[i][j-1],st[i+(1<<j-1)][j-1]);
        for(int i=1;i+Y-1<=m;i++)s[k][i]=query(i,i+Y-1);
    }
    for(int k=1;k<=m;k++){
        for(int i=1;i<=n;i++)st[i][0]=s[i][k];
        for(int j=1;(1<<j)<=n;j++)
            for(int i=1;i+(1<<j)-1<=n;i++)
                st[i][j]=max(st[i][j-1],st[i+(1<<j-1)][j-1]);
        for(int i=1;i+X-1<=n;i++)a[i][k]=query(i,i+X-1);
    }
    for(int i=1;i+X-1<=n;i++){
        for(int j=1;j+Y-1<=m;j++)cout<<a[i][j]<<" ";
        cout<<"\n";
    }
    return 0;
}
